worklistUpdationRule:
'use strict';
({params, imports}) => {
  const workLists = params.workLists;
  const context = params.context;
  const WorkItem = imports.models.WorkItem;
  const _ = imports.lodash;

  function generateUUID() {
    const t = new Date().getTime();
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      const r = (t + Math.random() * 16) % 16 | 0;
      return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
    });
  }

  const currentWorkItem = workLists.getCurrentWorkItem();
  if (!currentWorkItem || !context || !context.entity) return workLists;

  const currentWorkList = workLists.currentWorkList;
  const entity = context.entity;

  if (currentWorkItem.type === WorkItem.type.REGISTRATION) {
    const subjectTypeName = _.get(entity, 'subjectType.name');

    // Flow 1: Activity Registration → Participant Registration
    if (subjectTypeName === 'Activity') {
      currentWorkList.workItems.splice(
        0, currentWorkList.workItems.length,
        new WorkItem(generateUUID(), WorkItem.type.REGISTRATION, { subjectTypeName: 'Participant' })
      );
    }

    // Flow 2: Participant Registration → Assessment & Distribution
    else if (subjectTypeName === 'Participant') {
      const subjectUUID = _.get(entity, 'uuid');
      if (subjectUUID) {
        currentWorkList.workItems.splice(
          0, currentWorkList.workItems.length,
          new WorkItem(generateUUID(), WorkItem.type.ENCOUNTER, {
            encounterType: 'Assessment & Distribution',
            subjectUUID: subjectUUID
          })
        );
      }
    }
  }

  else if (currentWorkItem.type === WorkItem.type.ENCOUNTER) {
    const encounterTypeName = _.get(entity, 'encounterType.name');

    // Flow 3: Assessment & Distribution → Participant Registration (loop)
    if (encounterTypeName === 'Assessment & Distribution') {
      currentWorkList.workItems.splice(
        0, currentWorkList.workItems.length,
        new WorkItem(generateUUID(), WorkItem.type.REGISTRATION, { subjectTypeName: 'Participant' })
      );
    }
  }

  return workLists;
};
